/**
 * Recipe Model
 * 
 * This file contains the Recipe model interface for database operations.
 */

import type { Recipe, InsertRecipe } from "@shared/schema";

// Recipe model interface for database operations
export interface IRecipeModel {
  findById(id: string): Promise<Recipe | undefined>;
  findByRestaurant(restaurantId: string): Promise<Recipe[]>;
  create(recipe: InsertRecipe): Promise<Recipe>;
  update(id: string, data: Partial<Recipe>): Promise<Recipe | undefined>;
  delete(id: string): Promise<boolean>;
}

shared/schema.ts.content:
import { sql } from "drizzle-orm";
import { pgTable, text, varchar, integer, timestamp, json, index, decimal, boolean, uuid } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// ============================================================================
// ENUMS
// ============================================================================

export const UserRole = {
  ADMIN: "admin",
  MANAGER: "manager",
  STAFF: "staff",
} as const;

export type UserRoleType = (typeof UserRole)[keyof typeof UserRole];

export const ChangeType = {
  DELIVERY: "Delivery",
  USAGE: "Usage",
  ADJUSTMENT: "Adjustment",
} as const;

export type ChangeTypeValue = (typeof ChangeType)[keyof typeof ChangeType];

// ============================================================================
// RESTAURANTS TABLE
// ============================================================================

export const restaurants = pgTable("restaurants", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  createdAt: timestamp("created_at").defaultNow(),
});

export const insertRestaurantSchema = createInsertSchema(restaurants).pick({
  name: true,
});

export type InsertRestaurant = z.infer<typeof insertRestaurantSchema>;
export type Restaurant = typeof restaurants.$inferSelect;

// ============================================================================
// USERS TABLE
// ============================================================================

export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  email: text("email").notNull().unique(),
  passwordHash: text("password_hash").notNull(),
  role: text("role").notNull().default(UserRole.STAFF),
  restaurantId: varchar("restaurant_id").references(() => restaurants.id),
  station: text("station"),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("users_email_idx").on(table.email),
  index("users_restaurant_idx").on(table.restaurantId),
  index("users_role_idx").on(table.role),
]);

export const insertUserSchema = createInsertSchema(users).pick({
  name: true,
  email: true,
  passwordHash: true,
  role: true,
  restaurantId: true,
  station: true,
});

export const registerUserSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  email: z.string().email("Invalid email address"),
  password: z.string().min(6, "Password must be at least 6 characters"),
  role: z.enum([UserRole.ADMIN, UserRole.MANAGER, UserRole.STAFF]).optional(),
  restaurantId: z.string().optional(),
});

export const loginSchema = z.object({
  email: z.string().email("Invalid email address"),
  password: z.string().min(1, "Password is required"),
});

export type InsertUser = z.infer<typeof insertUserSchema>;
export type User = typeof users.$inferSelect;
export type RegisterCredentials = z.infer<typeof registerUserSchema>;
export type LoginCredentials = z.infer<typeof loginSchema>;

// JWT Payload type
export interface JWTPayload {
  userId: string;
  email: string;
  role: UserRoleType;
  restaurantId: string | null;
}

// ============================================================================
// INVENTORY ITEMS TABLE
// ============================================================================

export const inventoryItems = pgTable("inventory_items", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  restaurantId: varchar("restaurant_id").notNull().references(() => restaurants.id),
  item: text("item"),
  storage: text("storage"),
  unit: text("unit"),
  quantity: decimal("quantity", { precision: 10, scale: 2 }).default("0"),
  lowStockThreshold: decimal("low_stock_threshold", { precision: 10, scale: 2 }).default("0"),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("inventory_restaurant_idx").on(table.restaurantId),
]);

export const insertInventoryItemSchema = createInsertSchema(inventoryItems).pick({
  restaurantId: true,
  item: true,
  storage: true,
  unit: true,
  quantity: true,
  lowStockThreshold: true,
});

// Client-facing schema (restaurantId is set by server from auth)
export const createInventoryItemSchema = z.object({
  item: z.string().min(1, "Item name is required").max(200),
  storage: z.string().max(200).optional(),
  unit: z.string().max(50).optional(),
  quantity: z.union([z.string(), z.number()]).optional().default("0"),
  lowStockThreshold: z.union([z.string(), z.number()]).optional().default("0"),
});

export const updateInventoryItemSchema = createInventoryItemSchema.partial();

export type InsertInventoryItem = z.infer<typeof insertInventoryItemSchema>;
export type InventoryItem = typeof inventoryItems.$inferSelect;

// ============================================================================
// INVENTORY LOGS TABLE
// ============================================================================

export const inventoryLogs = pgTable("inventory_logs", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  inventoryItemId: varchar("inventory_item_id").notNull().references(() => inventoryItems.id),
  restaurantId: varchar("restaurant_id").notNull().references(() => restaurants.id),
  changeType: text("change_type").notNull(), // "Delivery" | "Usage" | "Adjustment"
  quantityChanged: decimal("quantity_changed", { precision: 10, scale: 2 }).notNull(),
  finalQuantity: decimal("final_quantity", { precision: 10, scale: 2 }).notNull(),
  createdAt: timestamp("created_at").defaultNow(),
  createdBy: varchar("created_by").references(() => users.id),
  notes: text("notes"),
}, (table) => [
  index("inventory_logs_item_idx").on(table.inventoryItemId),
  index("inventory_logs_restaurant_idx").on(table.restaurantId),
  index("inventory_logs_created_at_idx").on(table.createdAt),
  index("inventory_logs_change_type_idx").on(table.changeType),
]);

export const insertInventoryLogSchema = createInsertSchema(inventoryLogs).pick({
  inventoryItemId: true,
  restaurantId: true,
  changeType: true,
  quantityChanged: true,
  finalQuantity: true,
  createdBy: true,
  notes: true,
});

// Client-facing schema for creating inventory logs
export const createInventoryLogSchema = z.object({
  inventoryItemId: z.string().min(1, "Inventory item is required"),
  changeType: z.enum([ChangeType.DELIVERY, ChangeType.USAGE, ChangeType.ADJUSTMENT], {
    errorMap: () => ({ message: "Invalid change type" }),
  }),
  quantityChanged: z.union([z.string(), z.number()]),
  notes: z.string().max(1000).optional(),
});

export const updateInventoryLogSchema = z.object({
  notes: z.string().max(1000).optional(),
});

export type InsertInventoryLog = z.infer<typeof insertInventoryLogSchema>;
export type InventoryLog = typeof inventoryLogs.$inferSelect;

// ============================================================================
// RECIPES TABLE
// ============================================================================

export const recipes = pgTable("recipes", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  name: text("name").notNull(),
  dishBase: text("dish_base"),
  instructions: text("instructions"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
  category: text("category"),
  diet: text("diet"),
  dishSauce: text("dish_sauce"),
  timingMinutes: integer("timing_minutes"),
  postType: text("post_type"),
  imageUrl: text("image_url"),
}, (table) => [
  index("recipes_name_idx").on(table.name),
  index("recipes_category_idx").on(table.category),
]);

export const insertRecipeSchema = createInsertSchema(recipes).pick({
  name: true,
  dishBase: true,
  instructions: true,
  category: true,
  diet: true,
  dishSauce: true,
  timingMinutes: true,
  postType: true,
  imageUrl: true,
});

// Client-facing schemas for recipe operations
export const createRecipeSchema = z.object({
  name: z.string().min(1, "Name is required").max(200),
  category: z.string().optional().nullable(),
  dishBase: z.string().max(200).optional().nullable(),
  dishSauce: z.string().max(200).optional().nullable(),
  diet: z.string().max(100).optional().nullable(),
  timingMinutes: z.number().int().positive().optional().nullable(),
  instructions: z.string().max(5000).optional().nullable(),
});

export const updateRecipeSchema = createRecipeSchema.partial();

export type InsertRecipe = z.infer<typeof insertRecipeSchema>;
export type Recipe = typeof recipes.$inferSelect;

// ============================================================================
// CLEANING TASKS TABLE
// ============================================================================

export const cleaningTasks = pgTable("cleaning_tasks", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  restaurantId: varchar("restaurant_id").notNull().references(() => restaurants.id),
  day: text("day"), // e.g., "Monday", "Tuesday", etc.
  isActive: boolean("is_active").default(true),
  station: text("station"), // e.g., "Kitchen", "Prep Area", "Front Counter"
  task: text("task"), // The specific cleaning task description
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("cleaning_tasks_restaurant_idx").on(table.restaurantId),
  index("cleaning_tasks_station_idx").on(table.station),
]);

export const insertCleaningTaskSchema = createInsertSchema(cleaningTasks).pick({
  restaurantId: true,
  day: true,
  isActive: true,
  station: true,
  task: true,
});

export type InsertCleaningTask = z.infer<typeof insertCleaningTaskSchema>;
export type CleaningTask = typeof cleaningTasks.$inferSelect;

// ============================================================================
// CLEANING LOGS TABLE
// ============================================================================

export const cleaningLogs = pgTable("cleaning_logs", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  cleaningTaskId: varchar("cleaning_task_id").notNull().references(() => cleaningTasks.id),
  completedBy: varchar("completed_by").notNull().references(() => users.id),
  completedAt: timestamp("completed_at").defaultNow(),
  notes: text("notes"),
}, (table) => [
  index("cleaning_logs_task_idx").on(table.cleaningTaskId),
  index("cleaning_logs_completed_by_idx").on(table.completedBy),
  index("cleaning_logs_completed_at_idx").on(table.completedAt),
]);

export const insertCleaningLogSchema = createInsertSchema(cleaningLogs).pick({
  cleaningTaskId: true,
  completedBy: true,
  notes: true,
});

export type InsertCleaningLog = z.infer<typeof insertCleaningLogSchema>;
export type CleaningLog = typeof cleaningLogs.$inferSelect;

export type CleaningLogWithDetails = CleaningLog & {
  taskName: string;
  station: string;
  day: string;
  username: string;
  restaurantId: string;
  restaurantName: string;
};

// ============================================================================
// USER AVAILABILITY TABLE
// ============================================================================

export const userAvailability = pgTable("user_availability", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id),
  restaurantId: varchar("restaurant_id").notNull().references(() => restaurants.id),
  dayOfWeek: integer("day_of_week").notNull(), // 0-6 (Sunday-Saturday)
  specificDate: text("specific_date"), // "YYYY-MM-DD" format, null for recurring weekly availability
  startTime: text("start_time").notNull(), // "HH:MM" format
  endTime: text("end_time").notNull(), // "HH:MM" format
  isAvailable: boolean("is_available").default(true),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("user_availability_user_idx").on(table.userId),
  index("user_availability_restaurant_idx").on(table.restaurantId),
  index("user_availability_day_idx").on(table.dayOfWeek),
  index("user_availability_date_idx").on(table.specificDate),
]);

export const insertUserAvailabilitySchema = createInsertSchema(userAvailability).pick({
  userId: true,
  restaurantId: true,
  dayOfWeek: true,
  specificDate: true,
  startTime: true,
  endTime: true,
  isAvailable: true,
});

export const createUserAvailabilitySchema = z.object({
  dayOfWeek: z.number().int().min(0).max(6),
  specificDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "Date must be in YYYY-MM-DD format").optional().nullable(),
  startTime: z.string().regex(/^\d{2}:\d{2}$/, "Time must be in HH:MM format"),
  endTime: z.string().regex(/^\d{2}:\d{2}$/, "Time must be in HH:MM format"),
  isAvailable: z.boolean().optional().default(true),
});

export type InsertUserAvailability = z.infer<typeof insertUserAvailabilitySchema>;
export type UserAvailability = typeof userAvailability.$inferSelect;

// ============================================================================
// SHIFTS TABLE
// ============================================================================

export const shifts = pgTable("shifts", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  restaurantId: varchar("restaurant_id").notNull().references(() => restaurants.id),
  shiftDate: text("shift_date").notNull(), // "YYYY-MM-DD" format
  startTime: text("start_time").notNull(), // "HH:MM" format
  endTime: text("end_time").notNull(), // "HH:MM" format
  station: text("station").notNull(), // e.g., "Kitchen", "Bar", "Counter"
  requiredStaff: integer("required_staff").default(1),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("shifts_restaurant_idx").on(table.restaurantId),
  index("shifts_date_idx").on(table.shiftDate),
  index("shifts_station_idx").on(table.station),
]);

export const insertShiftSchema = createInsertSchema(shifts).pick({
  restaurantId: true,
  shiftDate: true,
  startTime: true,
  endTime: true,
  station: true,
  requiredStaff: true,
});

export const createShiftSchema = z.object({
  shiftDate: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, "Date must be in YYYY-MM-DD format"),
  startTime: z.string().regex(/^\d{2}:\d{2}$/, "Time must be in HH:MM format"),
  endTime: z.string().regex(/^\d{2}:\d{2}$/, "Time must be in HH:MM format"),
  station: z.string().min(1, "Station is required"),
  requiredStaff: z.number().int().positive().optional().default(1),
});

export type InsertShift = z.infer<typeof insertShiftSchema>;
export type Shift = typeof shifts.$inferSelect;

// ============================================================================
// SHIFT ASSIGNMENTS TABLE
// ============================================================================

export const ShiftAssignmentStatus = {
  ASSIGNED: "assigned",
  CONFIRMED: "confirmed",
  SWAPPED: "swapped",
} as const;

export type ShiftAssignmentStatusType = (typeof ShiftAssignmentStatus)[keyof typeof ShiftAssignmentStatus];

export const shiftAssignments = pgTable("shift_assignments", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  shiftId: varchar("shift_id").notNull().references(() => shifts.id, { onDelete: "cascade" }),
  userId: varchar("user_id").notNull().references(() => users.id),
  status: text("status").notNull().default(ShiftAssignmentStatus.ASSIGNED),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("shift_assignments_shift_idx").on(table.shiftId),
  index("shift_assignments_user_idx").on(table.userId),
]);

export const insertShiftAssignmentSchema = createInsertSchema(shiftAssignments).pick({
  shiftId: true,
  userId: true,
  status: true,
});

export const createShiftAssignmentSchema = z.object({
  shiftId: z.string().min(1, "Shift is required"),
  userId: z.string().min(1, "User is required"),
});

export type InsertShiftAssignment = z.infer<typeof insertShiftAssignmentSchema>;
export type ShiftAssignment = typeof shiftAssignments.$inferSelect;

export type ShiftWithAssignments = Shift & {
  assignments: (ShiftAssignment & { userName?: string })[];
};

// ============================================================================
// TIME ENTRIES TABLE (Clock In/Out)
// ============================================================================

export const TimeEntryStatus = {
  OPEN: "open",
  CLOSED: "closed",
  EDITED: "edited",
} as const;

export type TimeEntryStatusType = (typeof TimeEntryStatus)[keyof typeof TimeEntryStatus];

export const timeEntries = pgTable("time_entries", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: uuid("user_id").notNull().references(() => users.id),
  shiftId: uuid("shift_id").references(() => shifts.id),
  restaurantId: uuid("restaurant_id").notNull().references(() => restaurants.id),
  clockInTime: timestamp("clock_in_time").notNull(),
  clockOutTime: timestamp("clock_out_time"),
  totalMinutes: integer("total_minutes"),
  status: text("status").notNull().default(TimeEntryStatus.OPEN),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => [
  index("time_entries_user_idx").on(table.userId),
  index("time_entries_restaurant_idx").on(table.restaurantId),
  index("time_entries_shift_idx").on(table.shiftId),
  index("time_entries_status_idx").on(table.status),
]);

export const insertTimeEntrySchema = createInsertSchema(timeEntries).pick({
  userId: true,
  shiftId: true,
  restaurantId: true,
  clockInTime: true,
  clockOutTime: true,
  totalMinutes: true,
  status: true,
});

export const clockInSchema = z.object({
  shiftId: z.string().optional(),
});

export const clockOutSchema = z.object({
  timeEntryId: z.string().min(1, "Time entry ID is required"),
});

export type InsertTimeEntry = z.infer<typeof insertTimeEntrySchema>;
export type TimeEntry = typeof timeEntries.$inferSelect;

