  editingRecipe,
  setEditingRecipe,
  onUpdate,
  onDelete,
  isUpdating,
}: {
  category: string;
  recipes: Recipe[];
  canEdit: boolean;
  editingRecipe: Recipe | null;
  setEditingRecipe: (recipe: Recipe | null) => void;
