import { useState } from "react";
import { useLocation, Link } from "wouter";
import { useMutation } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, setAuthToken } from "@/lib/queryClient";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import { Loader2, LogIn } from "lucide-react";

const loginSchema = z.object({
  email: z.string().email("Invalid email address"),
  password: z.string().min(1, "Password is required"),
});

type LoginFormData = z.infer<typeof loginSchema>;

export default function Login() {
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const { setUser } = useAuth();

  const form = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      email: "",
      password: "",
    },
  });

  const loginMutation = useMutation({
    mutationFn: async (data: LoginFormData) => {
      const res = await apiRequest("POST", "/api/auth/login", data);
      return res.json();
    },
    onSuccess: (data) => {
      setAuthToken(data.accessToken);
      setUser(data.user);
      toast({
        title: "Welcome back!",
        description: `Logged in as ${data.user.name}`,
      });
      // Small delay to ensure state updates propagate before navigation
      setTimeout(() => {
        navigate("/landing");
      }, 50);
    },
    onError: (error: Error) => {
      toast({
        variant: "destructive",
        title: "Login failed",
        description: error.message || "Invalid email or password",
      });
    },
  });

  const onSubmit = (data: LoginFormData) => {
    loginMutation.mutate(data);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <Card className="w-full max-w-md" data-testid="card-login">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl font-bold" data-testid="text-login-title">Sign In</CardTitle>
          <CardDescription>Enter your credentials to access the dashboard</CardDescription>
        </CardHeader>
        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Email</FormLabel>
                    <FormControl>
                      <Input
                        type="email"
                        placeholder="you@example.com"
                        data-testid="input-email"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="password"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Password</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Your password"
                        data-testid="input-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <Button
                type="submit"
                className="w-full"
                disabled={loginMutation.isPending}
                data-testid="button-login"
              >
                {loginMutation.isPending ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <LogIn className="h-4 w-4 mr-2" />
                )}
                Sign In
              </Button>
            </form>
          </Form>
          <div className="mt-4 text-center text-sm text-muted-foreground">
            New here?{" "}
            <Link href="/signup" className="text-primary hover:underline" data-testid="link-signup">
              Create an account
            </Link>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

server/routes/recipe.routes.ts.content:
/**
 * Recipe Routes
 * 
 * CRUD operations for recipes.
 * Recipes are shared across all restaurants (no restaurant_id column).
 * - All authenticated users can view recipes
 * - Only admin/manager can create, edit, delete
 */

import { Router } from "express";
import { storage } from "../storage";
import { createRecipeSchema, updateRecipeSchema, UserRole } from "@shared/schema";
import { 
  authenticateToken, 
  authorizeRoles 
} from "../middleware/auth.middleware";

const router = Router();

// Get all recipes (shared across all restaurants)
router.get("/", authenticateToken, async (req, res) => {
  try {
    const recipes = await storage.getAllRecipes();
    res.json({ recipes });
  } catch (error) {
    console.error("Error fetching recipes:", error);
    res.status(500).json({ message: "Failed to fetch recipes" });
  }
});

// Get single recipe by ID
router.get("/:id", authenticateToken, async (req, res) => {
  try {
    const recipe = await storage.getRecipe(req.params.id);

    if (!recipe) {
      return res.status(404).json({ message: "Recipe not found" });
    }

    res.json({ recipe });
  } catch (error) {
    console.error("Error fetching recipe:", error);
    res.status(500).json({ message: "Failed to fetch recipe" });
  }
});

// Create recipe (admin/manager only)
router.post(
  "/",
  authenticateToken,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req, res) => {
    try {
      const validation = createRecipeSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({ 
          message: "Invalid recipe data",
          errors: validation.error.flatten()
        });
      }

      const recipe = await storage.createRecipe(validation.data);
      res.status(201).json({ recipe });
    } catch (error) {
      console.error("Error creating recipe:", error);
      res.status(500).json({ message: "Failed to create recipe" });
    }
  }
);

// Update recipe (admin/manager only)
router.patch(
  "/:id",
  authenticateToken,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req, res) => {
    try {
      const recipe = await storage.getRecipe(req.params.id);

      if (!recipe) {
        return res.status(404).json({ message: "Recipe not found" });
      }

      const validation = updateRecipeSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({ 
          message: "Invalid update data",
          errors: validation.error.flatten()
        });
      }

      const updatedRecipe = await storage.updateRecipe(req.params.id, {
        ...validation.data,
        updatedAt: new Date(),
      });

      res.json({ recipe: updatedRecipe });
    } catch (error) {
      console.error("Error updating recipe:", error);
      res.status(500).json({ message: "Failed to update recipe" });
    }
  }
);

// Delete recipe (admin/manager only)
router.delete(
  "/:id",
  authenticateToken,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req, res) => {
    try {
      const recipe = await storage.getRecipe(req.params.id);

      if (!recipe) {
        return res.status(404).json({ message: "Recipe not found" });
      }

      await storage.deleteRecipe(req.params.id);
      res.json({ message: "Recipe deleted successfully" });
    } catch (error) {
      console.error("Error deleting recipe:", error);
      res.status(500).json({ message: "Failed to delete recipe" });
    }
  }
);

export default router;

