import { useState } from "react";
import { useLocation, Link } from "wouter";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, setAuthToken } from "@/lib/queryClient";
import { useAuth } from "@/hooks/use-auth";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { Loader2, UserPlus } from "lucide-react";
import type { Restaurant } from "@shared/schema";

const signupSchema = z.object({
  name: z.string().min(2, "Name must be at least 2 characters"),
  email: z.string().email("Invalid email address"),
  password: z.string().min(6, "Password must be at least 6 characters"),
  confirmPassword: z.string().min(1, "Please confirm your password"),
  restaurantId: z.string().min(1, "Please select a restaurant"),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords do not match",
  path: ["confirmPassword"],
});

type SignupFormData = z.infer<typeof signupSchema>;

export default function Signup() {
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const { setUser } = useAuth();

  const form = useForm<SignupFormData>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      name: "",
      email: "",
      password: "",
      confirmPassword: "",
      restaurantId: "",
    },
  });

  const { data: restaurantsData, isLoading: isLoadingRestaurants } = useQuery<{ restaurants: Restaurant[] }>({
    queryKey: ["/api/restaurants"],
  });

  const restaurantList = restaurantsData?.restaurants ?? [];

  const signupMutation = useMutation({
    mutationFn: async (data: SignupFormData) => {
      const { confirmPassword, ...registerData } = data;
      const res = await apiRequest("POST", "/api/auth/register", registerData);
      return res.json();
    },
    onSuccess: (data) => {
      setAuthToken(data.accessToken);
      setUser(data.user);
      toast({
        title: "Account created!",
        description: `Welcome, ${data.user.name}!`,
      });
      // Small delay to ensure state updates propagate before navigation
      setTimeout(() => {
        navigate("/landing");
      }, 50);
    },
    onError: (error: Error) => {
      toast({
        variant: "destructive",
        title: "Registration failed",
        description: error.message || "Could not create account",
      });
    },
  });

  const onSubmit = (data: SignupFormData) => {
    signupMutation.mutate(data);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4">
      <Card className="w-full max-w-md" data-testid="card-signup">
        <CardHeader className="text-center">
          <CardTitle className="text-2xl font-bold" data-testid="text-signup-title">Create Account</CardTitle>
          <CardDescription>Sign up to start managing your inventory</CardDescription>
        </CardHeader>
        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
              <FormField
                control={form.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Full Name</FormLabel>
                    <FormControl>
                      <Input
                        type="text"
                        placeholder="John Smith"
                        data-testid="input-name"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="email"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Email</FormLabel>
                    <FormControl>
                      <Input
                        type="email"
                        placeholder="you@example.com"
                        data-testid="input-email"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="password"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Password</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="At least 6 characters"
                        data-testid="input-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="confirmPassword"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Confirm Password</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Confirm your password"
                        data-testid="input-confirm-password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="restaurantId"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Restaurant</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value} disabled={isLoadingRestaurants}>
                      <FormControl>
                        <SelectTrigger data-testid="select-restaurant">
                          <SelectValue placeholder={isLoadingRestaurants ? "Loading restaurants..." : "Select a restaurant"} />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        {restaurantList.map((restaurant) => (
                          <SelectItem 
                            key={restaurant.id} 
                            value={restaurant.id}
                            data-testid={`select-restaurant-${restaurant.id}`}
                          >
                            {restaurant.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <Button
                type="submit"
                className="w-full"
                disabled={signupMutation.isPending}
                data-testid="button-signup"
              >
                {signupMutation.isPending ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <UserPlus className="h-4 w-4 mr-2" />
                )}
                Create Account
              </Button>
            </form>
          </Form>
          <div className="mt-4 text-center text-sm text-muted-foreground">
            Already have an account?{" "}
            <Link href="/login" className="text-primary hover:underline" data-testid="link-login">
              Sign in
            </Link>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

server/routes/inventory.routes.ts.content:
/**
 * Inventory Routes
 * 
 * API routes for inventory item operations.
 * All routes require authentication and restaurant isolation.
 * 
 * Permissions:
 * - GET: All authenticated users (staff, manager, admin)
 * - POST/PATCH/DELETE: Admin and Manager only
 */

import { Router, type Request, type Response } from "express";
import { storage } from "../storage";
import { authenticateToken, requireRestaurant, authorizeRoles } from "../middleware/auth.middleware";
import { UserRole, createInventoryItemSchema, updateInventoryItemSchema } from "@shared/schema";

const router = Router();

/**
 * Search inventory items by name
 * GET /api/inventory/search?q=query&limit=10
 * 
 * Fast, case-insensitive search limited to user's restaurant.
 * Returns up to `limit` matching items (default: 10, max: 50)
 */
router.get("/search", authenticateToken, requireRestaurant, async (req: Request, res: Response) => {
  try {
    const { q, limit } = req.query;
    const query = typeof q === "string" ? q : "";
    const maxResults = Math.min(
      Math.max(1, parseInt(limit as string) || 10),
      50
    );

    if (!req.user?.restaurantId) {
      return res.status(400).json({ message: "Restaurant ID required" });
    }

    const results = await storage.searchInventoryItems(
      req.user.restaurantId,
      query,
      maxResults
    );

    res.json({ items: results });
  } catch (error) {
    console.error("Search inventory error:", error);
    res.status(500).json({ message: "Internal server error" });
  }
});

/**
 * Get all inventory items for user's restaurant
 * GET /api/inventory
 */
router.get("/", authenticateToken, requireRestaurant, async (req: Request, res: Response) => {
  try {
    if (!req.user?.restaurantId) {
      return res.status(400).json({ message: "Restaurant ID required" });
    }

    const items = await storage.getInventoryItemsByRestaurant(req.user.restaurantId);
    res.json({ items });
  } catch (error) {
    console.error("Get inventory error:", error);
    res.status(500).json({ message: "Internal server error" });
  }
});

/**
 * Get low stock items for user's restaurant
 * GET /api/inventory/low-stock
 */
router.get("/low-stock", authenticateToken, requireRestaurant, async (req: Request, res: Response) => {
  try {
    if (!req.user?.restaurantId) {
      return res.status(400).json({ message: "Restaurant ID required" });
    }

    const items = await storage.getLowStockItems(req.user.restaurantId);
    res.json({ items });
  } catch (error) {
    console.error("Get low stock items error:", error);
    res.status(500).json({ message: "Internal server error" });
  }
});

/**
 * Get single inventory item by ID
 * GET /api/inventory/:id
 */
router.get("/:id", authenticateToken, requireRestaurant, async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const item = await storage.getInventoryItem(id);

    if (!item) {
      return res.status(404).json({ message: "Inventory item not found" });
    }

    // Restaurant isolation check
    if (item.restaurantId !== req.user?.restaurantId) {
      return res.status(403).json({ message: "Access denied" });
    }

    res.json({ item });
  } catch (error) {
    console.error("Get inventory item error:", error);
    res.status(500).json({ message: "Internal server error" });
  }
});

/**
 * Create inventory item (admin/manager only)
 * POST /api/inventory
 */
router.post(
  "/",
  authenticateToken,
  requireRestaurant,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req: Request, res: Response) => {
    try {
      const validation = createInventoryItemSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({
          message: "Invalid inventory item data",
          errors: validation.error.flatten(),
        });
      }

      const itemData = {
        ...validation.data,
        restaurantId: req.user!.restaurantId!,
        quantity: String(validation.data.quantity),
        lowStockThreshold: String(validation.data.lowStockThreshold),
      };

      const item = await storage.createInventoryItem(itemData);
      res.status(201).json({ item });
    } catch (error) {
      console.error("Create inventory item error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  }
);

/**
 * Update inventory quantity (all authenticated users)
 * PATCH /api/inventory/:id/quantity
 * 
 * Automatically creates an inventory log entry to track the change
 */
router.patch(
  "/:id/quantity",
  authenticateToken,
  requireRestaurant,
  async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const { quantity, changeType } = req.body;

      if (quantity === undefined || quantity === null) {
        return res.status(400).json({ message: "Quantity is required" });
      }

      const existingItem = await storage.getInventoryItem(id);

      if (!existingItem) {
        return res.status(404).json({ message: "Inventory item not found" });
      }

      if (existingItem.restaurantId !== req.user?.restaurantId) {
        return res.status(403).json({ message: "Access denied" });
      }

      const oldQuantity = parseFloat(existingItem.quantity || "0");
      const newQuantity = parseFloat(String(quantity));
      const quantityChanged = newQuantity - oldQuantity;

      // Update the item first
      const updatedItem = await storage.updateInventoryItem(id, {
        quantity: String(quantity),
      });

      // Only create a log if the quantity actually changed
      if (quantityChanged !== 0) {
        // Determine change type based on the change or use provided type
        let logChangeType = changeType;
        if (!logChangeType) {
          if (quantityChanged > 0) {
            logChangeType = "Delivery";
          } else {
            logChangeType = "Usage";
          }
        }

        // Create inventory log entry using the item's restaurantId (supports admin restaurant selector)
        await storage.createInventoryLog({
          inventoryItemId: id,
          restaurantId: existingItem.restaurantId,
          changeType: logChangeType,
          quantityChanged: String(quantityChanged),
          finalQuantity: String(newQuantity),
          createdBy: req.user!.userId,
          notes: null,
        });
      }

      res.json({ item: updatedItem });
    } catch (error) {
      console.error("Update inventory quantity error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  }
);

/**
 * Update inventory item (admin/manager only)
 * PATCH /api/inventory/:id
 */
router.patch(
  "/:id",
  authenticateToken,
  requireRestaurant,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const existingItem = await storage.getInventoryItem(id);

      if (!existingItem) {
        return res.status(404).json({ message: "Inventory item not found" });
      }

      // Restaurant isolation check
      if (existingItem.restaurantId !== req.user?.restaurantId) {
        return res.status(403).json({ message: "Access denied" });
      }

      const validation = updateInventoryItemSchema.safeParse(req.body);
      if (!validation.success) {
        return res.status(400).json({
          message: "Invalid update data",
          errors: validation.error.flatten(),
        });
      }

      // Ensure restaurantId cannot be changed
      const updateData: Record<string, unknown> = { ...validation.data };
      delete updateData.restaurantId;

      if (updateData.quantity !== undefined) {
        updateData.quantity = String(updateData.quantity);
      }
      if (updateData.lowStockThreshold !== undefined) {
        updateData.lowStockThreshold = String(updateData.lowStockThreshold);
      }
      updateData.updatedAt = new Date();

      const updatedItem = await storage.updateInventoryItem(id, updateData);
      res.json({ item: updatedItem });
    } catch (error) {
      console.error("Update inventory item error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  }
);

/**
 * Delete inventory item (admin/manager only)
 * DELETE /api/inventory/:id
 */
router.delete(
  "/:id",
  authenticateToken,
  requireRestaurant,
  authorizeRoles(UserRole.ADMIN, UserRole.MANAGER),
  async (req: Request, res: Response) => {
    try {
      const { id } = req.params;
      const existingItem = await storage.getInventoryItem(id);

      if (!existingItem) {
        return res.status(404).json({ message: "Inventory item not found" });
      }

      // Restaurant isolation check
      if (existingItem.restaurantId !== req.user?.restaurantId) {
        return res.status(403).json({ message: "Access denied" });
      }

      await storage.deleteInventoryItem(id);
      res.json({ message: "Inventory item deleted successfully" });
    } catch (error) {
      console.error("Delete inventory item error:", error);
      res.status(500).json({ message: "Internal server error" });
    }
  }
);

export default router;

